document.addEventListener("DOMContentLoaded",function (){const sections = document.querySelectorAll(".about,.services,.why-choose-us,.testimonials,.contact");function revealOnScroll(){sections.forEach((section) =>{const sectionTop = section.getBoundingClientRect().top;if (sectionTop < window.innerHeight - 100){section.classList.add("show");}});}window.addEventListener("scroll",revealOnScroll);revealOnScroll();});document.addEventListener("DOMContentLoaded",function (){const hamburger = document.querySelector(".hamburger");const nav = document.querySelector("nav");hamburger.addEventListener("click",function (event){event.stopPropagation();nav.classList.toggle("active");});document.addEventListener("click",function (event){if (!nav.contains(event.target) && !hamburger.contains(event.target)){nav.classList.remove("active");}});}); function toggleBlogContent(e){var t=e.nextElementSibling;"none"===t.style.display||""===t.style.display?(t.style.display="block",e.textContent="Sembunyikan"):(t.style.display="none",e.textContent="Baca Selengkapnya");}

